const _ = require("lodash");
const problemsData = require("../../data/problems.json");

/**
 * Normalize tags to lowercase trimmed strings
 * @param {string|string[]} tags
 * @returns {string[]}
 */
function normalizeTags(tags) {
  if (!tags) return [];
  if (typeof tags === "string") {
    // split by comma and trim
    return tags
      .split(",")
      .map(t => t.trim().toLowerCase())
      .filter(t => t.length > 0);
  }
  if (Array.isArray(tags)) {
    return tags
      .map(t => (typeof t === "string" ? t.trim().toLowerCase() : ""))
      .filter(t => t.length > 0);
  }
  return [];
}

/**
 * Filter problems by difficulty, tags, and limit
 * @param {Object} options
 * @param {string} [options.difficulty] - difficulty filter (exact match)
 * @param {string|string[]} [options.tags] - tags filter (case-insensitive, comma-separated or array)
 * @param {number} [options.limit] - max number of problems to return
 * @returns {Object} - { problems: Array, metadata: Object }
 */
function getProblems({ difficulty, tags, limit } = {}) {
  let filtered = problemsData;

  // Filter by difficulty if provided
  if (difficulty) {
    filtered = filtered.filter(p => p.difficulty === difficulty);
  }

  // Normalize and filter by tags if provided
  const normalizedTags = normalizeTags(tags);
  if (normalizedTags.length > 0) {
    filtered = filtered.filter(problem => {
      if (!problem.tags || !Array.isArray(problem.tags)) return false;
      const problemTagsLower = problem.tags.map(t => t.toLowerCase());
      // All normalizedTags must be present in problemTagsLower
      return normalizedTags.every(t => problemTagsLower.includes(t));
    });
  }

  // Sort by stable criteria: difficulty asc, then id asc
  filtered = _.orderBy(filtered, ["difficulty", "id"], ["asc", "asc"]);

  // Apply limit if provided
  if (typeof limit === "number" && limit >= 0) {
    filtered = filtered.slice(0, limit);
  }

  // Compose metadata with normalized tag filters
  const metadata = {
    count: filtered.length,
    filters: {
      difficulty: difficulty || null,
      tags: normalizedTags,
      limit: typeof limit === "number" ? limit : null
    }
  };

  return { problems: filtered, metadata };
}

module.exports = {
  getProblems
};
